  1	import React, { FC, MouseEvent, ReactNode, SFC } from 'react';
  2	import classnames from 'classnames';
  3	import * as _ from 'lodash-es';
  4	
  5	import {
  6	  getGroupVersionKindForResource,
  7	  K8sResourceKind,
  8	  useK8sModel,
  9	} from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Breadcrumb,
 12	  BreadcrumbItem,
 13	  Button,
 14	  Popover,
 15	  Split,
 16	  SplitItem,
 17	} from '@patternfly/react-core';
 18	import { PencilAltIcon } from '@patternfly/react-icons/dist/esm/icons/pencil-alt-icon';
 19	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 20	
 21	import { getPropertyDescription } from './swagger';
 22	
 23	export const PropertyPath: FC<{
 24	  kind: string;
 25	  path: string | string[];
 26	}> = ({ kind, path }) => {
 27	  const pathArray: string[] = _.toPath(path);
 28	  return (
 29	    <Breadcrumb className="co-breadcrumb">
 30	      <BreadcrumbItem>{kind}</BreadcrumbItem>
 31	      {pathArray.map((property, i) => {
 32	        const isLast = i === pathArray.length - 1;
 33	        return (
 34	          <BreadcrumbItem isActive={isLast} key={i}>
 35	            {property}
 36	          </BreadcrumbItem>
 37	        );
 38	      })}
 39	    </Breadcrumb>
 40	  );
 41	};
 42	
 43	const EditButton: SFC<EditButtonProps> = (props) => {
 44	  return (
 45	    <Button
 46	      data-test={
 47	        props.testId ? `${props.testId}-details-item__edit-button` : 'details-item__edit-button'
 48	      }
 49	      isInline
 50	      onClick={props.onClick}
 51	      type="button"
 52	      variant="link"
 53	    >
 54	      {props.children}
 55	      <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
 56	    </Button>
 57	  );
 58	};
 59	
 60	export const DetailsItem: FC<DetailsItemProps> = ({
 61	  canEdit = true,
 62	  children,
 63	  defaultValue = '-',
 64	  description,
 65	  editAsGroup,
 66	  hideEmpty,
 67	  label,
 68	  labelClassName,
 69	  obj,
 70	  onEdit,
 71	  path,
 72	  valueClassName,
 73	}) => {
 74	  const { t } = useNetworkingTranslation();
 75	
 76	  const [model] = useK8sModel(obj ? getGroupVersionKindForResource(obj) : '');
 77	
 78	  const hide = hideEmpty && _.isEmpty(_.get(obj, path));
 79	  const popoverContent: string = description ?? getPropertyDescription(model, path);
 80	  const value: ReactNode = children || _.get(obj, path, defaultValue);
 81	  const editable = onEdit && canEdit;
 82	  return hide ? null : (
 83	    <>
 84	      <dt
 85	        className={classnames('details-item__label', labelClassName)}
 86	        data-test-selector={`details-item-label__${label}`}
 87	      >
 88	        <Split>
 89	          <SplitItem className="details-item__label">
 90	            {popoverContent || path ? (
 91	              <Popover
 92	                headerContent={<div>{label}</div>}
 93	                {...(popoverContent && {
 94	                  bodyContent: <div className="co-pre-line">{popoverContent}</div>,
 95	                })}
 96	                {...(path && {
 97	                  footerContent: <PropertyPath kind={model?.kind} path={path} />,
 98	                })}
 99	                maxWidth="30rem"
100	              >
101	                <Button className="details-item__popover-button" data-test={label} variant="plain">
102	                  {label}
103	                </Button>
104	              </Popover>
105	            ) : (
106	              label
107	            )}
108	          </SplitItem>
109	          {editable && editAsGroup && (
110	            <>
111	              <SplitItem isFilled />
112	              <SplitItem>
113	                <EditButton onClick={onEdit} testId={label}>
114	                  {t('Edit')}
115	                </EditButton>
116	              </SplitItem>
117	            </>
118	          )}
119	        </Split>
120	      </dt>
121	      <dd
122	        className={classnames('details-item__value', valueClassName, {
123	          'details-item__value--group': editable && editAsGroup,
124	        })}
125	        data-test-selector={`details-item-value__${label}`}
126	      >
127	        {editable && !editAsGroup ? (
128	          <EditButton onClick={onEdit} testId={label}>
129	            {value}
130	          </EditButton>
131	        ) : (
132	          value
133	        )}
134	      </dd>
135	    </>
136	  );
137	};
138	
139	export type DetailsItemProps = {
140	  canEdit?: boolean;
141	  defaultValue?: ReactNode;
142	  description?: string;
143	  editAsGroup?: boolean;
144	  hideEmpty?: boolean;
145	  label: string;
146	  labelClassName?: string;
147	  obj?: K8sResourceKind;
148	  onEdit?: (e: MouseEvent<HTMLButtonElement>) => void;
149	  path?: string | string[];
150	  valueClassName?: string;
151	};
152	
153	type EditButtonProps = {
154	  onClick: (e: MouseEvent<HTMLButtonElement>) => void;
155	  testId?: string;
156	};
157	
158	DetailsItem.displayName = 'DetailsItem';
159	PropertyPath.displayName = 'PropertyPath';
160	EditButton.displayName = 'EditButton';

